There are $n$ functions numbered from $1$ to $n$. Function $1$ is the main entry of the program.

- $cnt[i]$ represents the total number of child functions directly invoked by function $i$.
- $call[i][j]$ represents the ID of the $j$-th child function called by function $i$. All child functions are invoked strictly in the given order.

You need to use a **linked stack with a head node** to simulate the execution of nested function calls. Print `Enter x `when starting to execute function $x$, and print `Exit x` when function $x$ finishes and exits.

```c
typedef struct node {
    int data;
    struct node *next;
} StackNode, *Stack;

void Push(Stack S, int data) {
    StackNode *p = (StackNode*)malloc(sizeof(StackNode));
    p->data = data;
    ;
    ;
}

int Pop(Stack S) {
    StackNode *p = S->next;
    int data = p->data;
    S->next = p->next;
    free(p);
    return data;
}

int GetTop(Stack S) {
    return S->next->data;
}

void Simulate(int call[][MAXN], int cnt[]) {
    int ptr[MAXN] = {0};
    
    StackNode head;
    Stack S = &head;
    S->next = NULL;

    Push(S, 1);
    printf("Enter 1\n");

    while () {
        int u = GetTop(S);
        
        if () {
            int v = call[u][ptr[u]++];
            Push(S, v);
            printf("Enter %d\n", v);
        } else {
            Pop(S);
            printf("Exit %d\n", u);
        }
    }
}
```

